bomData.valueScript:
// Filter function to get all the hardware elements for the adjustable shelf
let HardwareElements = GlobalFunc.find_HardwareLibraryMapping(part.pa_HardwareId);

// Cycle to add all hardware elements to the BOM
HardwareElements.forEach(info => {
  let elem = this.addbomout_Hardware();
  let ShelfadjFittingBOMInfo = GlobalFunc.find_HardwareLibrary(info.SupplierArticleNumber!,info.Supplier!);
  let ShelfadjFittingBOMName = GlobalFunc.find_PartSettings("part_ShelfadjFitting");

  elem.bom_Supplier=info.Supplier;
  elem.bom_SupplierArticle=info.SupplierArticleNumber;
  elem.bom_Description1=ShelfadjFittingBOMInfo.Description;
  elem.bom_Description2=ShelfadjFittingBOMInfo.Description2;
  elem.bom_Length=ShelfadjFittingBOMInfo.Length;
  elem.bom_Width=ShelfadjFittingBOMInfo.Width;
  elem.bom_Thk=ShelfadjFittingBOMInfo.Thickness;
  elem.bom_Color=ShelfadjFittingBOMInfo.Color;
  elem.bom_Weight=ShelfadjFittingBOMInfo.Weight;
  elem.bom_Name=ShelfadjFittingBOMName.BomPartDescription;
  elem.bom_Type=part._partId;
  elem.bom_PartId=part._id;
  elem.bom_ParentId=parentId;
  elem.bom_Qty=info.BomQty;
})
